from typing import List

def max_product(words: List[str]) -> int:
    n = len(words)
    masks = [0] * n
    for i, word in enumerate(words):
        for ch in word:
            masks[i] |= 1 << (ord(ch) - ord('a'))

    max_prod = 0
    for i in range(n):
        for j in range(i + 1, n):
            if (masks[i] & masks[j]) == 0:
                max_prod = max(max_prod, len(words[i]) * len(words[j]))
    return max_prod
